// Digital Dice using 7-Segment display
const int segPins[] = {2, 3, 4, 5, 6, 7, 8};
const int btnPin = 9;
const byte numPatterns[] = {
  0b00111111, // 0
  0b00000110, // 1
  0b01011011, // 2
  0b01001111, // 3
  0b01100110, // 4
  0b01101101, // 5
  0b01111101, // 6
};

void setup() {
  for(int i=0; i<7; i++) pinMode(segPins[i], OUTPUT);
  pinMode(btnPin, INPUT);
  randomSeed(analogRead(0));
}

void loop() {
  if(digitalRead(btnPin) == HIGH) {
    int val = random(1, 7);
    showNumber(val);
    delay(500);
  }
}

void showNumber(int num) {
  for(int i=0; i<7; i++) {
    digitalWrite(segPins[i], bitRead(numPatterns[num], i));
  }
}

// Standard Traffic Light Timing Sequence
void setup() {
  pinMode(10, OUTPUT); // Red
  pinMode(9, OUTPUT);  // Yellow
  pinMode(8, OUTPUT);  // Green
}

void loop() {
  // Green Light on
  digitalWrite(8, HIGH); digitalWrite(9, LOW); digitalWrite(10, LOW);
  delay(5000);
  // Yellow Light on
  digitalWrite(8, LOW); digitalWrite(9, HIGH); digitalWrite(10, LOW);
  delay(2000);
  // Red Light on
  digitalWrite(8, LOW); digitalWrite(9, LOW); digitalWrite(10, HIGH);
  delay(5000);
}

#include <SPI.h>
#include <MFRC522.h>
#include <Servo.h>

#define SS_PIN 10
#define RST_PIN 9
MFRC522 rfid(SS_PIN, RST_PIN);
Servo lock;

void setup() {
  SPI.begin();
  rfid.PCD_Init();
  lock.attach(6);
  lock.write(0); // Locked
}

void loop() {
  if ( ! rfid.PICC_IsNewCardPresent()) return;
  if ( ! rfid.PICC_ReadCardSerial()) return;

  // Hardcoded master tag verification
  if (rfid.uid.uidByte[0] == 0xDE && rfid.uid.uidByte[1] == 0xAD) {
    lock.write(90); // Unlock
    delay(3000);
    lock.write(0);  // Relock
  }
}

