#include <LiquidCrystal.h>
LiquidCrystal lcd(12, 11, 5, 4, 3, 2);
volatile boolean running = false;
volatile unsigned long elapsed = 0;

void setup() {
  lcd.begin(16, 2);
  attachInterrupt(0, startStopISR, FALLING);
}

void startStopISR() {
  running = !running;
}

void loop() {
  if (running) {
    elapsed++;
    lcd.setCursor(0, 0);
    lcd.print(elapsed / 10.0);
    delay(100);
  }
}

#include <Wire.h>
#include <LiquidCrystal_I2C.h>

LiquidCrystal_I2C lcd(0x27, 16, 2);

void setup() {
  lcd.begin(16, 2);
}

void loop() {
  int val = analogRead(A0);
  float mv = (val / 1023.0) * 5000.0;
  float temp = mv / 10.0; // LM35: 10mV per degree C

  lcd.setCursor(0,0);
  lcd.print("Temp: ");
  lcd.print(temp);
  lcd.print(" C");
  delay(1000);
}

void setup() {
  pinMode(3, OUTPUT);
}

void loop() {
  int val = analogRead(A0);
  float voltage = val * 5.0 / 1023.0;
  float tempC = (voltage - 0.5) * 100.0;

  if(tempC > 30.0) {
    int speed = map(tempC, 30, 45, 100, 255);
    analogWrite(3, constrain(speed, 100, 255));
  } else {
    analogWrite(3, 0);
  }
  delay(1000);
}
